import React, { useEffect, useRef } from 'react';

const VideoFrame = ({ src, onError }) => {
  const containerRef = useRef(null);

  useEffect(() => {
    if (src && containerRef.current) {
      // Crear iframe dinámicamente para evitar detección
      const frame = document.createElement('iframe');

      // Configurar atributos de forma dinámica
      const attrs = {
        'src': src,
        'width': '100%',
        'height': '100%',
        'frameborder': '0',
        'allowfullscreen': 'true',
        'allow': 'autoplay; fullscreen; picture-in-picture',
        'sandbox': 'allow-scripts allow-same-origin allow-presentation allow-forms',
        'referrerpolicy': 'no-referrer-when-downgrade',
        'loading': 'lazy'
      };

      Object.keys(attrs).forEach(key => {
        frame.setAttribute(key, attrs[key]);
      });

      // Estilos para evitar detección
      frame.style.cssText = `
        border: none;
        outline: none;
        background: #000;
        border-radius: 8px;
        width: 100%;
        height: 100%;
      `;

      // Limpiar contenedor y agregar iframe
      containerRef.current.innerHTML = '';
      containerRef.current.appendChild(frame);

      // Detectar si el iframe fue bloqueado
      const checkBlocked = () => {
        try {
          // Si no podemos acceder o está vacío, probablemente bloqueado
          if (!frame.contentWindow || frame.contentWindow.location.href === 'about:blank') {
            console.log('Iframe posiblemente bloqueado');
            if (onError) onError();
          }
        } catch (e) {
          // Error de CORS es normal, pero si es otro error...
          if (e.message.includes('blocked') || e.message.includes('denied')) {
            console.log('Iframe definitivamente bloqueado:', e.message);
            if (onError) onError();
          }
        }
      };

      // Verificar después de cargar
      frame.onload = () => {
        setTimeout(checkBlocked, 2000);
      };

      // Manejar errores directos
      frame.onerror = () => {
        console.log('Error directo del iframe');
        if (onError) onError();
      };

      return () => {
        if (containerRef.current) {
          containerRef.current.innerHTML = '';
        }
      };
    }
  }, [src, onError]);

  return (
    <div 
      ref={containerRef}
      className="w-full h-96 md:h-[500px] lg:h-[600px] bg-black rounded-lg"
      style={{ minHeight: '400px' }}
    />
  );
};

export default VideoFrame;
